#include<bits/stdc++.h>
using namespace std;
long long exgcd(long long a,long long b,long long &x,long long &y)
{
    if(b==0)
    {
        x=1;
        y=0;
        return a;
    }
    long long g=exgcd(b,a%b,x,y);
    long long tx=x;
    x=y;
    y=tx-(a/b)*y;
    return g;
}
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        long long a,b,c,x,y;
        scanf("%lld%lld%lld",&a,&b,&c);
        long long g=exgcd(a,b,x,y);
        if(c%g!=0)
        {
            printf("-1\n");
            continue;
        }
        long long x_0=x*(c/g);
        long long y_0=y*(c/g);
        long long p=ceil(1.0*(1-x_0)/(b/g));
        long long minx=x_0+p*(b/g);
        long long maxy=y_0-p*(a/g);
        if(maxy<=0)
        {
            long long miny=(maxy%(a/g)+(a/g))%(a/g);
            if(miny==0)
            {
                miny=a/g;
            }
            printf("%lld %lld\n",minx,miny);
        }
        else
        {
            long long miny=(maxy%(a/g)+(a/g))%(a/g);
            if(miny==0)
            {
                miny=a/g;
            }
            long long maxx=(c-miny*b)/a;
            long long cnt=(maxy-miny)/(a/g)+1;
            printf("%lld %lld %lld %lld %lld\n",cnt,minx,miny,maxx,maxy);
        }
    }
    return 0;
}
